doc.service_worker_registration:
// Enregistrement du Service Worker (dans sw.js)
self.addEventListener('install', function(event) {
  event.waitUntil(
    caches.open(CACHE_NAME).then(function(cache) {
      return cache.addAll(ASSETS);
    })
  );
});

// Gestionnaire d'installation (dans install-handler.js)
if (typeof InstallHandler !== 'undefined') {
  InstallHandler.init();
  InstallHandler.install();  // Déclenche l'installation
}

// Mise à jour automatique (dans auto-updater.js)
AutoUpdate.start();  // Vérifie GitHub toutes les 10 minutes

